         * Chronicle event id, when the command produced one (most do; idempotent
         * replays do not).
         */eventId: String?,
        /**
         * Canonical JSON-encoded `serde_json::Value` returned by the engine.
         */resultJson: String) {
        self.commandId = commandId
        self.eventId = eventId
        self.resultJson = resultJson
    }
}



