/**
 * Outcome of a batch ingest.
 */
public struct IngestReport {
    /**
     * Events newly written.
     */
    public var accepted: UInt32
    /**
     * Events that were already present (id collision; idempotent skip).
     */
    public var skipped: UInt32
    /**
     * Per-event rejection reasons. Empty when everything was either
     * accepted or skipped.
     */
    public var rejected: [String]

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(
        /**
         * Events newly written.
         */accepted: UInt32,
        /**
         * Events that were already present (id collision; idempotent skip).
         */skipped: UInt32,
        /**
         * Per-event rejection reasons. Empty when everything was either
         * accepted or skipped.
         */rejected: [String]) {
        self.accepted = accepted
        self.skipped = skipped
        self.rejected = rejected
    }
}



extension IngestReport: Equatable, Hashable {
    public static func ==(lhs: IngestReport, rhs: IngestReport) -> Bool {
        if lhs.accepted != rhs.accepted {
            return false
        }
        if lhs.skipped != rhs.skipped {
            return false
        }
        if lhs.rejected != rhs.rejected {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(accepted)
        hasher.combine(skipped)
        hasher.combine(rejected)
    }
}


