/**
 * FFI-safe flattening of [`ActantError`].
 *
 * Several `ActantError` variants collapse into the same FFI variant on
 * purpose — Swift / Kotlin consumers don't need every internal distinction
 * the Rust side draws. The mapping table:
 *
 * | `ActantError`           | `FfiError`           |
 * |-------------------------|----------------------|
 * | `Storage`               | `Storage`            |
 * | `Internal`              | `Storage`            |
 * | `NotImplemented`        | `Storage`            |
 * | `NotFound`              | `NotFound`           |
 * | `InvalidInput`          | `InvalidInput`       |
 * | `Conflict`              | `InvalidInput`       |
 * | `PermissionDenied`      | `PermissionDenied`   |
 * | `PolicyHalt`            | `PermissionDenied`   |
 * | `ApprovalDenied`        | `PermissionDenied`   |
 * | `ApprovalRequired`      | `ApprovalRequired`   |
 * | `IdempotentReplay`      | `IdempotentReplay`   |
 *
 * `RateLimited` has no current source in `ActantError`; it's reserved for
 * future throttle-driven failures wired through [`actant-reliability`].
 */
public enum FfiError {



    /**
     * Underlying storage / I/O failure.
     */
    case Storage(message: String)

    /**
     * The named resource doesn't exist.
     */
    case NotFound(message: String)

    /**
     * Caller-supplied input failed validation or a conflict check.
     */
    case InvalidInput(message: String)

    /**
     * Policy refused the action outright.
     */
    case PermissionDenied(message: String)

    /**
     * Policy requires a human approval before the action can proceed.
     */
    case ApprovalRequired(message: String)

    /**
     * Caller is being throttled (reserved; not produced today).
     */
    case RateLimited(message: String)

    /**
     * Idempotency key matched a prior command — see the prior outcome.
     */
    case IdempotentReplay(message: String)

}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeFfiError: FfiConverterRustBuffer {
    typealias SwiftType = FfiError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> FfiError {
        let variant: Int32 = try readInt(&buf)
        switch variant {




        case 1: return .Storage(
            message: try FfiConverterString.read(from: &buf)
        )

        case 2: return .NotFound(
            message: try FfiConverterString.read(from: &buf)
        )

        case 3: return .InvalidInput(
            message: try FfiConverterString.read(from: &buf)
        )

        case 4: return .PermissionDenied(
            message: try FfiConverterString.read(from: &buf)
        )

        case 5: return .ApprovalRequired(
            message: try FfiConverterString.read(from: &buf)
        )

        case 6: return .RateLimited(
            message: try FfiConverterString.read(from: &buf)
        )

        case 7: return .IdempotentReplay(
            message: try FfiConverterString.read(from: &buf)
        )


        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: FfiError, into buf: inout [UInt8]) {
        switch value {




        case .Storage(_ /* message is ignored*/):
            writeInt(&buf, Int32(1))
        case .NotFound(_ /* message is ignored*/):
            writeInt(&buf, Int32(2))
        case .InvalidInput(_ /* message is ignored*/):
            writeInt(&buf, Int32(3))
        case .PermissionDenied(_ /* message is ignored*/):
            writeInt(&buf, Int32(4))
        case .ApprovalRequired(_ /* message is ignored*/):
            writeInt(&buf, Int32(5))
        case .RateLimited(_ /* message is ignored*/):
            writeInt(&buf, Int32(6))
        case .IdempotentReplay(_ /* message is ignored*/):
            writeInt(&buf, Int32(7))


        }
    }
}


